package com.socialblog.comment.application;import com.socialblog.comment.api.*;import com.socialblog.comment.api.CommentDtos.*;import com.socialblog.comment.domain.*;import com.socialblog.comment.repository.*;import org.springframework.data.domain.*;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.UUID;
@Service public class CommentService{private final CommentRepository comments;private final ArticleProjectionRepository articles;private final OutboxEventRepository outbox;private final DomainEventFactory events;public CommentService(CommentRepository c,ArticleProjectionRepository a,OutboxEventRepository o,DomainEventFactory e){comments=c;articles=a;outbox=o;events=e;}@Transactional public Response create(UUID author,CreateRequest r){ArticleProjection article=articles.findById(r.articleId()).filter(ArticleProjection::isActive).orElseThrow(()->new ApiException(HttpStatus.CONFLICT,"ARTICLE_NOT_AVAILABLE","Article is not published or no longer exists"));UUID recipient=article.getAuthorId();if(r.parentId()!=null){Comment p=find(r.parentId());if(!p.getArticleId().equals(r.articleId())||p.getStatus()!=Comment.Status.ACTIVE)throw new ApiException(HttpStatus.BAD_REQUEST,"INVALID_PARENT_COMMENT","Parent comment is invalid");recipient=p.getAuthorId();}Comment c=comments.save(new Comment(r.articleId(),author,r.parentId(),r.content()));outbox.save(events.created(c,recipient));return map(c);}@Transactional public Response update(UUID id,UUID author,UpdateRequest r){Comment c=owned(id,author);c.update(r.content());return map(c);}@Transactional public void delete(UUID id,UUID author){Comment c=owned(id,author);if(c.getStatus()!=Comment.Status.DELETED){c.delete();outbox.save(events.deleted(c));}}@Transactional(readOnly=true)public Page<Response>article(UUID id,Pageable p){return comments.findByArticleIdOrderByCreatedAtAsc(id,p).map(this::map);}private Comment owned(UUID id,UUID author){Comment c=find(id);if(!c.getAuthorId().equals(author))throw new ApiException(HttpStatus.FORBIDDEN,"COMMENT_FORBIDDEN","Only the author can modify this comment");return c;}private Comment find(UUID id){return comments.findById(id).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,"COMMENT_NOT_FOUND","Comment not found"));}private Response map(Comment c){return new Response(c.getId(),c.getArticleId(),c.getAuthorId(),c.getParentId(),c.getContent(),c.getStatus().name(),c.getCreatedAt(),c.getUpdatedAt());}}
